import json

# Batch 1: Q1-Q70
# Using hex to avoid any encoding issues during file transfer
hex_data = ""

translations = json.loads(bytes.fromhex(hex_data).decode('utf-8'))

with open('src/data/questions.json', 'r', encoding='utf-8') as f:
    data = json.load(f)

for q in data:
    q_id = str(q['id'])
    if q_id in translations:
        if 'explanation' not in q:
            q['explanation'] = {}
        q['explanation']['vi_question'] = translations[q_id]

with open('src/data/questions.json', 'w', encoding='utf-8') as f:
    json.dump(data, f, ensure_ascii=False, indent=2)

print("Restored Q1-Q3 (Hex Test).")
